#include<bits/stdc++.h>
using namespace std;

queue<char> q;
int ans=0,cnt=0,n;
string s;
char a[10];
void zeng1(int x,int y){
    a[x]=' ';
    a[y]=' ';
    ans+=2;
    q.push(s[++cnt]);
    return;
}
bool pan1(){
    bool flag=0;
    for(int i=1;i<=9;i++){
        for(int j=i+1;j<=9;j++){
            if(a[i]==a[j]&&a[i]!=' '&&a[j]!=' '){
                flag=1;
                zeng1(i,j);
            }
        }
    }
    return flag;
}
void zeng2(){
    for(int i=1;i<=8;i++)  q.push(s[++cnt]);
    return;
}
bool pan2(){
    bool flag=1;
    for(int i=1;i<=9;i++) if(a[i]!=' ') flag=0;
    if(flag) zeng2();
    return flag;
}
void zeng3(){
        ans+=9;
    for(int i=1;i<=9;i++){
        a[i]=' ';
    }
     for(int i=1;i<=10;i++)  q.push(s[++cnt]);
}
bool pan3(){
    bool flag=1;
    for(int i=1;i<=9;i++) if(a[i]==' ') flag=0;
     for(int i=1;i<=9;i++){
        for(int j=i+1;j<=9;j++){
            if(a[i]==a[j]){
                flag=0;
                break;
            }
        }
    }
    if(flag) zeng3();
    return flag;
}
bool huan1(){
    int flag=0;
    if(pan1()){
        flag=1;
    }
    if(pan2()){
        flag=1; 
    }
    if(pan3()){
       flag=1;  
     }
    if(!flag){
        for(int i=1;i<=9;i++) if(a[i]!=' ') ans++;
        return 0;
    }
    return 1;
}
void huan2(){
    for(int i=1;i<=9;i++){
        if(a[i]==' '){
            if(!q.empty()){
                a[i]=q.front();
                q.pop();
            }
        }
    }
    return;
}
void solve(){
    cin>>s;
    cin>>n;
    for(int i=1;i<=9;i++) a[i]=' ';
    for(int i=0;i<n;i++){
        q.push(s[i]);
    }
    cnt=n-1;
    huan2();
    while(huan1()){
        huan2();
    }
}
int main(){
    solve();
    cout<<ans;
}
